-- Kids Quest Hub / RoboCity Quest
-- Advanced game update: interactive robot route, digital desktop/browser/mail/chat/AI/password games, Scratch block quests.
-- Run this AFTER 001_schema_and_seed.sql in Supabase SQL Editor.

alter table public.rooms add column if not exists level_limit integer default 10;

-- Fix for existing DB created by 001_schema_and_seed.sql:
-- the original game_levels.type check allowed only ('choice','sort','build'),
-- while advanced interactive levels use type='game'.
alter table public.game_levels drop constraint if exists game_levels_type_check;
alter table public.game_levels add constraint game_levels_type_check
  check (type in ('choice', 'sort', 'build', 'game'));


update public.games set duration_minutes = 90, description = 'Повноцінна місія з маршрутом робота: поле, перешкоди, вантажі, ремонт, симуляція і перенесення на WeDo 2.0 / Spike Prime.', cover_emoji = '🤖' where id = '20000000-0000-4000-8000-000000000001';
update public.games set duration_minutes = 90, description = 'Цифрове місто з імітаціями робочого столу, браузера, пошти, чатів, паролів та навчання ШІ.', cover_emoji = '🛡️' where id = '20000000-0000-4000-8000-000000000002';
update public.games set duration_minutes = 90, description = 'Scratch Arcade з міні-сценою, блоками, запуском програми й переходом до реального Scratch-проєкту.', cover_emoji = '🐱' where id = '20000000-0000-4000-8000-000000000003';

delete from public.game_levels where game_id in ('20000000-0000-4000-8000-000000000001','20000000-0000-4000-8000-000000000002','20000000-0000-4000-8000-000000000003');

